INSERT INTO `dr_1_anlixianchang` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `nrydbdt`, `nrydbdbt`, `nrydbxbt`, `nrydbdljs`, `nrysgsp`, `nrysgspfm`, `nrykhhp`, `nrysgxc`) VALUES
(25, 16, '豫工机械湿喷台车助力中铁隧道局开工大吉!', '370', '案例现场1', '案例现场1', 1, 1, '创始人', 9, '/show-25.html', 0, 0, '127.0.0.1-53890', 1650698694, 1651225424, 0, '257', '豫工机械湿喷台车助力中铁隧道局开工大吉!', '湿喷台车 湿喷机械手', '宜兴铁路ZQ-3标项目，由中铁隧道局承建，计划采购液压湿喷机用于铁路隧道喷浆支护施工。\r\n客户在实地考察公司的生产规模后，对公司的生产能力很放心，为保证工期不误，客户决定采购生产效率更高的湿喷台车机械手（生产效率30㎥/h），并且一次采购两台。\r\n\r\n\r\n', '249', '250', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;施工现场，操作人员使用无线遥控进行喷射作业，远离作业面，不仅操作方便，更增加了工人的安全性。客户对设备高效的生产能力很满意，表示：根据工程需要，下次再上一台。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165120285143d76b.jpg&quot; title=&quot;GPKUFQUK$5~M2IHYZVV.jpg&quot; alt=&quot;GPKUFQUK$5~M2IHYZVV.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512028517de25c.jpg&quot; title=&quot;GCGXOS_0Y28AHZ`$GNWU.jpg&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165120285270d9ad.jpg&quot; title=&quot;修改.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512028517de25c.jpg&quot; title=&quot;GCGXOS_0Y28AHZ`$GNWU.jpg&quot; alt=&quot;GCGXOS_0Y28AHZ`$GNWU.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651202851e17172.jpg&quot; title=&quot;573XYBT@H7GBIC%PYDKTBI.jpg&quot; alt=&quot;573XYBT@H7GBIC%PYDKTBI.jpg&quot;/&gt;&lt;/p&gt;'),
(26, 16, '中交二航局梅观高速小导管冲孔项目', '317', '案例现场2', '案例现场2案例现场2案例现场2案例现场2案例现场2案例现场2案例现场2', 1, 1, '创始人', 9, '/show-26.html', 0, 0, '127.0.0.1-53939', 1650698738, 1651220172, 0, '213', '中交二航局梅观高速小导管冲孔项目', '超前小导管缩尖机    全自动数控小导管冲孔机', '中交二航局梅观高速清湖南段市政道路工程施工项目，配套豫工机械生产的工程设备全自动数控小导管冲孔机、缩尖机设备，用于超前小导管的缩尖、冲孔加工。该设备以其低噪音、高效率、缩尖模具耐久度的特点，获得客户好评。通过更换模具，即可达到加工不同型材的要求，帮助客户大大降低施工成本。', '207', '208', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;之前听同行抱怨自己买的管工设备，定位精度低、孔距不标准,但是这次购买的设备使用半年没有发现这类问题，这款设备易操作，产量高，性能稳定、工件成形时间短，效率高，而且加工的工件表面光滑，无伤痕，机器可长时间正常运行。机器模具更换简单，更换模具，可加工不同形状金属管，满足不同需求。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651144710729c13.jpg&quot; title=&quot;0~`I93~)TNNTK0)DS2R0(E.jpg&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651144710b4e4aa.jpg&quot; title=&quot;)4Q5B3WSSSQ4V33DAIYDH~B.jpg&quot; alt=&quot;)4Q5B3WSSSQ4V33DAIYDH~B.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651144710473830.jpg&quot; title=&quot;8PBJ~S0N%YR8NO7~VX%G.jpg&quot; alt=&quot;8PBJ~S0N%YR8NO7~VX%G.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651144710d56bff.jpg&quot; title=&quot;Q%4C%XTTCU4FWI@2H2RAR.jpg&quot; alt=&quot;Q%4C%XTTCU4FWI@2H2RAR.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(27, 16, '中铁二十四局工程模板桥梁模板加工', '248', '案例现场3', '案例现场3', 1, 1, '创始人', 9, '/show-27.html', 0, 0, '127.0.0.1-53967', 1650698765, 1651202127, 0, '247', '中铁二十四局工程模板桥梁模板加工', '等离子切割机  切割宽度：2.3m', '中铁二十四局的项目，工程模板、桥梁模板大钢板等离子切割，在使用过程中，设备以其运行平稳，切割精准，省时省力省人工，品质稳定，价格实惠，性价比高的特点，得到客户的好评，赢得客户信任，让客户在使用一个月后，返单豫工液压联合冲剪机。', '26', '27', '&lt;p&gt;&lt;span style=&quot;text-align: right;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;订购豫工的这台等离子切割机在工作过程中运行平稳、精准度高、双边驱动，效率高，是隧道大金属板高效切割的最佳选择，到目前为止，没有出现任何故障，减少了维修时间和费用，提高了生产效率。另外，设备物流给力，技术人员及时到现场调试培训，虽然是第一次合作，却让我对豫工机械很省心，必须为这个企业点赞。&amp;nbsp;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-align: right;&quot;&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512019461956bc.jpg&quot; title=&quot;等离子切割机安装调试&quot; alt=&quot;等离子切割机安装调试&quot; width=&quot;792&quot; height=&quot;593&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165120194785a8a3.jpg&quot; title=&quot;等离子切割机安装调试&quot; alt=&quot;等离子切割机安装调试&quot; width=&quot;792&quot; height=&quot;366&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512019476e63f9.jpg&quot; title=&quot;等离子切割机切割现场&quot; alt=&quot;等离子切割机切割现场&quot; width=&quot;792&quot; height=&quot;593&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651201947b7b62b.jpg&quot; title=&quot;等离子切割机工作现场&quot; alt=&quot;等离子切割机工作现场&quot; width=&quot;792&quot; height=&quot;366&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(10050, 16, '中铁五局京昆高速钢筋笼生产现场', '284', '4模拟数据', '5模拟数据', 1, 1, '创始人', 9, '/show-10050.html', 0, 0, '1.192.3.22-21644', 1651145314, 1651212524, 0, '229', '中铁五局京昆高速钢筋笼生产现场', '钢筋笼绕筋机 12米绕筋10分钟成型', '中铁五局集团G5京昆高速广元至绵阳段扩容工程，钢筋笼加工项目。设备以其运行平稳，加工精度高，加工速度快，省时省力省人工，品质稳定，价格实惠，性价比高的特点，得到客户好评，赢得客户信任。', '222', '223', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0);&quot;&gt;这款钢筋笼绕筋机自动化程度高，使用过程中中无须过多操作人员。因此，减少了人力资源的投入。设备采用数控技术，生产效率高，产品达标、间距均匀，可以长时间稳定运行，使我企业项目按照工期顺利推进。 另外，豫工的技术员经验很丰富，免费上门指导，不仅安装调试速度很快，对工人培训很有耐心，能够很快熟练操作！&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651198924ce9c34.jpg&quot; title=&quot;15429611185722303.jpg&quot; alt=&quot;15429611185722303.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651198925a64908.png&quot; title=&quot;CBOBXHQ%L~BZ7P@BL)%3)B.png&quot; alt=&quot;CBOBXHQ%L~BZ7P@BL)%3)B.png&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16511989245c461c.png&quot; title=&quot;5MF0@~@1X42RZ)SK35PDD.png&quot; alt=&quot;5MF0@~@1X42RZ)SK35PDD.png&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651198924c2169c.png&quot; title=&quot;~(6QB(T~G%VYRWA5)PCF.png&quot; alt=&quot;~(6QB(T~G%VYRWA5)PCF.png&quot;/&gt;&lt;/p&gt;'),
(10051, 16, '豫工液压湿喷机助力中铁18局地铁站建设', '259', '', '', 1, 2, '楠楠', 9, '/show-10051.html', 0, 0, '123.52.21.128-36176', 1651203276, 1651230905, 0, '268', '豫工液压湿喷机助力中铁18局地铁站建设', '液压湿喷机  生产能力:7立方/h', '徐州奥体中心地铁站项目，由中铁十八局承建，此次订购的液压湿喷机主要用于地铁基坑支护施工。\r\n客户之前订购的转子式喷浆机，因为工人反馈一直有堵管现象，影响工期，不得已重新订购！为保证客户工期不误，工厂安排物流发专车连夜为客户送货。', '260', '261', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;客户盛赞豫工液压湿喷机湿喷效果杠杠滴，现场操作工人说：这设备陡起（徐州方言：太厉害的意思），很好！到目前为止，没有听到工人反馈任何故障问题，这也减少了维修时间和费用，提高了生产效率。&lt;/span&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;另外，服务也很给力，工厂连夜发专车送货！技术人员第一时间到场调试，很专业也很有耐心！虽然是第一次合作，却让我很省心，为这样负责的企业点赞。&amp;nbsp;&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651204383717551.jpg&quot; title=&quot;2021_12_12_10_57_IMG_4625.jpg&quot; alt=&quot;2021_12_12_10_57_IMG_4625.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512043833ab291.jpg&quot; title=&quot;2021_12_12_14_34_IMG_4631.jpg&quot; alt=&quot;2021_12_12_14_34_IMG_4631.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165120438343b2df.jpg&quot; title=&quot;2021_12_14_09_44_IMG_4687.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651204383cf98e0.jpg&quot; title=&quot;2021_12_12_14_34_IMG_4635.jpg&quot;/&gt;&lt;/p&gt;'),
(10052, 16, '豫工液压湿喷机助战郑州地铁8号线建设', '316', '', '', 1, 2, '楠楠', 9, '/show-10052.html', 0, 0, '123.52.21.128-60059', 1651204673, 1651225522, 0, '285', '豫工液压湿喷机助战郑州地铁8号线建设', '90型单喷头液压湿喷机 ', '中国水电7局，隶属于中国电建，承建郑州地铁8号线建设项目。客户对喷射距离、产品质量、售后服务非常看重，曾亲自到工厂考察，对工厂生产实力、产品品质很放心。', '280', '281', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;感谢豫工售后人员的鼎力支持！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！选择豫工，就是省心！&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651205457e396ea.jpg&quot; title=&quot;IMG_20210206_111153730.jpg&quot; alt=&quot;IMG_20210206_111153730.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651205456bef3b6.jpg&quot; title=&quot;IMG_20210206_100559394.jpg&quot; alt=&quot;IMG_20210206_100559394.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165120545631c707.jpg&quot; title=&quot;IMG_20210206_103723167.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651205456220095.jpg&quot; title=&quot;IMG_20210206_105812133.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651205456d374a8.jpg&quot; title=&quot;IMG_20210206_110558.jpg&quot; alt=&quot;IMG_20210206_110558.jpg&quot;/&gt;&lt;/p&gt;'),
(10053, 16, '中铁三局承建的机场环线铁路项目', '293', '', '', 1, 2, '楠楠', 9, '/show-10053.html', 0, 0, '123.52.21.128-63411', 1651213193, 1651225634, 0, '294', '中铁三局承建的机场环线铁路项目', '90MINI型液压湿喷机 基坑支护', '中铁三局承建的机场环线铁路项目，建设地点：兰州市 \r\n建设规模：新建兰州中川国际机场综合交通枢纽环线铁路项目，新建线路长14.152公里，其中机场线10.889公里，联络线长3.263公里。设站3座，即新建T3航站楼站，改建兰州新区站和中川机场站。设线路所2个，即机场北线路所和史喇口线路所。\r\n', '291', '292', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;span style=&quot;font-size: 18px; letter-spacing: 0.544px; text-align: justify; background-color: rgb(255, 255, 255);&quot;&gt;因为之前购买联合上料喷浆车的合作，一直在朋友圈关注豫工的发展动态，了解到客户对于液压湿喷机使用反馈一直很好，一直在出货！此次工地需要该设备，就直接下单了，现在看来，施工&lt;/span&gt;&lt;span style=&quot;font-size: 18px; margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; text-align: justify; background-color: rgb(255, 255, 255); color: rgb(255, 0, 0); box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;strong style=&quot;margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;效果果然不错&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 18px; letter-spacing: 0.544px; text-align: justify; background-color: rgb(255, 255, 255);&quot;&gt;，完全满足基坑支护的需求，&lt;/span&gt;&lt;span style=&quot;font-size: 18px; margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; text-align: justify; background-color: rgb(255, 255, 255); color: rgb(255, 25, 2); box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;strong style=&quot;margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;选&lt;/strong&gt;&lt;strong style=&quot;margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;择豫工，就是放心&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 18px; letter-spacing: 0.544px; text-align: justify; background-color: rgb(255, 255, 255);&quot;&gt;。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651213682987ce4.jpg&quot; title=&quot;2021_10_08_10_19_IMG_3485.jpg&quot; alt=&quot;2021_10_08_10_19_IMG_3485.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512136833fd890.jpg&quot; title=&quot;2021_10_08_11_43_IMG_3520.jpg&quot; alt=&quot;2021_10_08_11_43_IMG_3520.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651213682d5fc8f.jpg&quot; title=&quot;2021_10_07_17_20_IMG_3468.jpg&quot; alt=&quot;2021_10_07_17_20_IMG_3468.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651213682b7b3b8.jpg&quot; title=&quot;2021_10_08_09_35_IMG_3481.jpg&quot; alt=&quot;2021_10_08_09_35_IMG_3481.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512136830558d5.jpg&quot; title=&quot;2021_10_08_11_42_IMG_3516.jpg&quot; alt=&quot;2021_10_08_11_42_IMG_3516.jpg&quot;/&gt;&lt;/p&gt;'),
(10054, 16, '中铁建工承建的湖南黄花机场改扩建工程', '295', '', '', 1, 2, '楠楠', 9, '/show-10054.html', 0, 0, '123.52.21.128-30577', 1651214555, 1651216653, 0, '303', '中铁建工承建的湖南黄花机场改扩建工程', '90型单喷头液压湿喷机 ', '机场工程包括长沙机场改扩建工程项目综合交通中心（GTC），建设综合交通中心工程总建筑面积206000平方米，与航站楼一体化设计，无边界化衔接，包括综合换乘中心43000平方米、停车楼163000平方米。\r\n高架桥工程指在T3航站楼前建设站前高架桥，总长1196米。\r\n', '296', '297', '&lt;p style=&quot;margin-top: 0px; margin-bottom: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(34, 34, 34); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; white-space: normal; background-color: rgb(250, 250, 239); line-height: 3em; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;喷浆支护过程中，赶上&lt;strong style=&quot;margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size: 18px; margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: rgb(255, 0, 0); box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;项目领导视察&lt;/span&gt;&lt;/strong&gt;现场！在观看液压湿喷机施工后，将豫工技术工程师找到身边，交流设备使用心得！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 0px; margin-bottom: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(34, 34, 34); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; white-space: normal; background-color: rgb(250, 250, 239); line-height: 3em; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;领导表示：项目上，曾经使用过其他厂家的&lt;span style=&quot;font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; background-color: rgb(255, 255, 255);&quot;&gt;转子式喷浆机，工人反馈一直有堵管现象，粉尘很大，影响工期&lt;/span&gt;，目前已不再使用。现在这款设备喷浆效果，与之前相比，&lt;strong style=&quot;margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: rgb(255, 0, 0); box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;效果不错&lt;/span&gt;&lt;/strong&gt;。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 0px; margin-bottom: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(34, 34, 34); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; white-space: normal; background-color: rgb(250, 250, 239); line-height: 3em; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;“在同一场地，同等地质条件下，豫工液压湿喷机与之前那款相比，喷浆&lt;strong style=&quot;margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px; margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: rgb(255, 0, 0); box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;速度更快，输送距离更更远&lt;/span&gt;&lt;/strong&gt;！”另一负责施工的领导介绍说。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651216515fb7f26.jpg&quot; title=&quot;2021_09_12_15_03_IMG_3194.jpg&quot; alt=&quot;2021_09_12_15_03_IMG_3194.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165121651536378e.jpg&quot; title=&quot;2021_09_12_15_13_IMG_3204.jpg&quot; alt=&quot;2021_09_12_15_13_IMG_3204.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651216515093f4b.jpg&quot; title=&quot;2021_09_12_15_56_IMG_3219.jpg&quot; alt=&quot;2021_09_12_15_56_IMG_3219.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/202204/033757ecafd45fb.jpg&quot; title=&quot;2021_09_12_16_28_IMG_3224&quot; alt=&quot;2021_09_12_16_28_IMG_3224&quot;/&gt;&lt;/p&gt;'),
(10055, 16, 'G204齐长城隧道工程', '305', '', '', 1, 2, '楠楠', 9, '/show-10055.html', 0, 0, '123.52.21.128-9899', 1651216724, 1651225546, 0, '308', 'G204齐长城隧道工程', '钢筋网片排焊机  网片焊机', 'G204公路为一级公路，设计速度为80km/h，位于青岛西海岸新区204国道黄山段、东石灰窑村南约700m处。本工程设进口、出口2个施工工区，分别由两洞口分界点掘进，开展左右线进出口4个工作面。主体工程采用进口侧左线掌子面超前，右线掌子面后续跟进，出口侧右线掌子面超前，左线掌子面后续跟进，分部开挖左右，衬砌完善配套多工作面推进的施工方案。', '306', '307', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;这款钢筋网片焊机设备焊点很牢固，自动落料，接速度很快，定位精准，网格尺寸很标准，在运行过程中没有出现任何故障，减少了维修时间和费用，提高了生产效率。而且实用性很强，运行成本低，节能环保，为我们避免了不必要的麻烦。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651218546866fca.jpg&quot; title=&quot;IMG_20210510_151932779.jpg&quot; alt=&quot;IMG_20210510_151932779.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651218546d098e1.jpg&quot; title=&quot;IMG_20210510_160602259.jpg&quot; alt=&quot;IMG_20210510_160602259.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512185478576cb.jpg&quot; title=&quot;IMG_20210510_161120409.jpg&quot; alt=&quot;IMG_20210510_161120409.jpg&quot;/&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/202204/78a0fe8143c9af5.jpg&quot; title=&quot;IMG_20210510_152808324_original&quot; alt=&quot;IMG_20210510_152808324_original&quot;/&gt;&lt;/p&gt;'),
(10056, 16, '重庆轨道交通18号线北延工程项目', '329', '', '', 1, 2, '楠楠', 9, '/show-10056.html', 0, 0, '123.52.21.128-50881', 1651220234, 1651225572, 0, '328', '重庆轨道交通18号线北延工程项目', '90型液压湿喷机', '建设地点：重庆市渝中区、九龙坡区\r\n建设规模：18号线为串联渝北、江北、南岸、渝中、九龙坡、巴南、大渡口的快速轨道交通骨干线路，线路全长约58.9km，设站38座。\r\n', '330', '331', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;豫工生产规模大，服务到位。他们根据我们项目实际情况推荐的液压湿喷机款式，非常适合施工需要，设备使用六个月了，没有出现任何故障，由于设计合理，提高了作业效率，让我们可以保证工期不误。&amp;nbsp;&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165122179548fa62.jpg&quot; title=&quot;QQ图片20220429163029&quot; alt=&quot;QQ图片20220429163029&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165122183471c10b.jpg&quot; title=&quot;QQ图片20220429163130.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165122183399d00b.jpg&quot; title=&quot;QQ图片20220429163016.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/165122183341a582.jpg&quot; title=&quot;QQ图片20220429162856.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512218349f7cbd.jpg&quot; title=&quot;QQ图片20220429163049.jpg&quot; alt=&quot;QQ图片20220429163049.jpg&quot;/&gt;&lt;/p&gt;'),
(10057, 16, '雄安容西市政工程一期四标段', '348', '', '', 1, 2, '楠楠', 9, '/show-10057.html', 0, 0, '123.52.21.128-16528', 1651222384, 1651223476, 0, '346', '雄安容西市政工程一期四标段', '钢筋网片排焊机 焊点牢固 自动落料', '容西片区位于雄安新区的西北部，西至安大线北延伸线，东至大水大街，北至津保高速市政，南至荣乌高速，是距离太行山（50公里）、定兴机场（20公里）最近的城市片区，该区域规划范围7.8平方公里。容西片区配套市政道路、综合管网、给排水设施工程（一期）总投资约54.388亿元。', '332', '333', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;网片排焊机自动化程度高，运转中无须过多操作人员。因此，减少了人力资源的投入，整机焊接牢度高，自动落料,焊接速度快,网格尺寸准确。公司急客户之所及，发货很及时，售后服务专业耐心，选择豫工，放心省心 。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651223210bdee81.jpg&quot; title=&quot;IMG_20210423_132429120.jpg&quot; alt=&quot;IMG_20210423_132429120.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512232115e5381.jpg&quot; title=&quot;IMG_20210423_145225358.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651223211b22b43.jpg&quot; title=&quot;IMG_20210424_094214484.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651223212c697af.jpg&quot; title=&quot;IMG_20210424_142355139.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651223210f46813.jpg&quot; title=&quot;IMG_20210423_135200177.jpg&quot;/&gt;&lt;/p&gt;'),
(10058, 16, '三门峡鸡笼网片排焊机服务项目', '368', '', '', 1, 2, '楠楠', 9, '/show-10058.html', 0, 0, '123.52.21.128-23332', 1651223591, 1651225023, 0, '369', '三门峡鸡笼网片排焊机服务项目', '钢筋网片排焊机 鸡笼网片焊机', '钢筋网片焊网机主要用于生产：桥梁建筑、水利工程、公路铁路、建筑浇筑混凝土用的钢筋网片，及建筑脚手架钢笆网片、隧道支护钢筋锚网。三门峡客户定制网片排焊机焊接宽度：1000mm，焊接长度：3000mm，焊接点数：6个 ，焊接直径：8-12mm。\r\n', '349', '350', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;“太厉害了吧，太厉害了，太厉害了！可以，可以！！”客户对设备试机结果给出最终评价。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;客户对豫工热情周到，省事省心的服务也非常满意，表示未来将持续关注豫工机械，期待未来的长期合作。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651224632df4107.jpg&quot; title=&quot;2021_01_06_10_54_IMG_0842.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512246322484b4.jpg&quot; title=&quot;2021_01_06_10_53_IMG_0840.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/16512246311a9767.jpg&quot; title=&quot;2021_01_06_10_02_IMG_0805.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651224631b4d130.jpg&quot; title=&quot;2021_01_06_09_51_IMG_0795.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202204/1651224633ed7128.jpg&quot; title=&quot;2021_01_06_11_33_IMG_0868.jpg&quot; alt=&quot;2021_01_06_11_33_IMG_0868.jpg&quot;/&gt;&lt;/p&gt;'),
(10073, 16, '泰国调试混凝土输送泵，助力一带一路建设！', '490', '混凝土输送泵,一带一路建设', '豫工机械出国售后，调试液压湿喷机、混凝土输送泵隧道物资设备', 1, 2, '楠楠', 9, '/show-10073.html', 0, 0, '123.160.152.15-27136', 1680926017, 1680926860, 0, '489', '混凝土输送泵泰国售后，助力一带一路建设', '豫工机械春季检修', '客户负责中泰高铁——超前支护工程项目。2021年9月，客户首次咨询豫工液压湿喷机，工字钢弯拱机等设备，同时咨询了河南、湖南至少5个生产厂家。2021年12月5日，客户到访公司总部——郑州运营中心，并考察了豫工机械隧道支护设备生产基地。客户看到豫工门类齐全的设备生产线，庞大的仓库备货，完全满足其隧道物资一站式采购的需求，非常满意，从而达成合作意向！', '487', '488', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 16px; background-color: rgb(255, 255, 255);&quot;&gt;感谢豫工对我们技术支持，派过来的工作人员很专业，很负责，带领工人对设备进行了全方位“体检”，以后我们用着就更放心了！听工人反映：检修之后，设备比之前更好用了！感谢豫工，免除了我的后顾之忧！近十年来，豫工机械以其“高性价比”的设备得到越来越多国外客户的认可，来司访问、工厂考察的客户络绎不绝，遍布全球100多个国家和地区，豫工质造，值得信赖！&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/202304/b38886be4681429.jpg&quot; title=&quot;2023_02_07_10_07_IMG_0853&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202304/1680861145ae6356.jpg&quot; title=&quot;2023_02_08_10_05_IMG_0914.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/ueditor/image/202304/1680861145ae7e5d.jpg&quot; title=&quot;2023_02_16_08_47_IMG_1458.jpg&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;http://www.ygsdjq.com/uploadfile/202304/68f735343a70c84.jpg&quot; title=&quot;2023_02_23_11_14_IMG_1646&quot;/&gt;&lt;/p&gt;');
INSERT INTO `dr_1_anlixianchang_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(25, 1, 16, '&lt;p&gt;&lt;span style=&quot;font-size: 20px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;与常规型液压湿喷机相比，工作效率提升2倍，轻松达到30㎥/h。&lt;/span&gt;&lt;/p&gt;'),
(26, 1, 16, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0);&quot;&gt;最大可加工50mm小导管及直径50mm以下的小导管，适用于隧道，地铁工地加工。新型钢材加工设备，隧道超前小导 管缩尖等各种领域的型材缩径加工。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(27, 1, 16, '&lt;p&gt;&lt;span style=&quot;text-align: right;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;white-space: normal; line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;切割宽度：2300mm 切割长度：6500mm&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;white-space: normal; line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;切割厚度：25mm&amp;nbsp; &amp;nbsp;切割速度：100-4000mm/min&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-align: right;&quot;&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;'),
(10050, 1, 16, '&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 20px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;12米绕筋，8-10分钟成型&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(10051, 2, 16, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0);&quot;&gt;液压湿喷机采用骨料粒径15mm，混凝土塌落度150-180的混凝土浆料，配合16/10型空压机，设备水平输送距离轻松达到80米，垂直喷射距离达到50米，生产能力每小时7立方。&lt;/span&gt;&lt;/p&gt;'),
(10052, 2, 16, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;90型单喷头液压湿喷机，具有泵送压力大、输送距离远、回弹率低、施工效率高等优势，生产能力7㎥/h,配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;/span&gt;&lt;/p&gt;'),
(10053, 2, 16, '&lt;p&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0); font-size: 20px;&quot;&gt;生产能力：7m3/h，&lt;span style=&quot;color: rgb(0, 0, 0); font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; background-color: rgb(255, 255, 255);&quot;&gt;配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;'),
(10054, 2, 16, '&lt;p style=&quot;box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; outline: 0px; background: transparent; -webkit-font-smoothing: antialiased; -webkit-tap-highlight-color: transparent; line-height: 1;&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; margin: 0px; padding: 0px; outline: 0px; background: transparent; -webkit-font-smoothing: antialiased; -webkit-tap-highlight-color: transparent; color: rgb(0, 0, 0); font-size: 20px;&quot;&gt;生产能力：7m3/h，&lt;span style=&quot;box-sizing: border-box; margin: 0px; padding: 0px; outline: 0px; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; -webkit-font-smoothing: antialiased; -webkit-tap-highlight-color: transparent;&quot;&gt;配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;'),
(10055, 2, 16, '&lt;p style=&quot;margin-bottom: 5px;line-height: 30px&quot;&gt;&lt;span style=&quot;font-size: 16px; font-family: 宋体;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;焊接宽度：1.5m&amp;nbsp; &amp;nbsp;焊接长度：2m&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;焊接点数：8点&amp;nbsp; &amp;nbsp; 焊接直径：5-8mm&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-bottom: 5px;line-height: 30px&quot;&gt;&lt;span style=&quot;font-size: 16px; font-family: Calibri;&quot;&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;'),
(10056, 2, 16, '&lt;p style=&quot;box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; outline: 0px; background: transparent; -webkit-font-smoothing: antialiased; -webkit-tap-highlight-color: transparent; line-height: 1;&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; margin: 0px; padding: 0px; outline: 0px; background: transparent; -webkit-font-smoothing: antialiased; -webkit-tap-highlight-color: transparent; color: rgb(0, 0, 0); font-size: 20px;&quot;&gt;生产能力：7-14m3/h，&lt;span style=&quot;box-sizing: border-box; margin: 0px; padding: 0px; outline: 0px; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; -webkit-font-smoothing: antialiased; -webkit-tap-highlight-color: transparent;&quot;&gt;配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;'),
(10057, 2, 16, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;焊接宽度：2000mm 焊接长度：6000mm&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;焊点数量：20个&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 焊接直径：8-9mm&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(10058, 2, 16, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;焊接宽度：1000mm 焊接长度：3000mm&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;焊接点数：6个&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 焊接直径：8-12mm&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(10073, 2, 16, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 16px; background-color: rgb(255, 255, 255);&quot;&gt;2022年2月，客户第一次下单2台双喷头液压湿喷机，并在之后的时间里持续复购，截至2022年底，客户已订购设备6次，总货款达千万以上。目前中泰铁路Muak LeK隧道四个站口，有三个站口都在使用豫工的设备。作为2022年的明星客户，中泰高铁Muak LeK隧道以其使用设备数量和使用时长，成为豫工2023春季巡检的第一站，检修对象包括液压湿喷机、混凝土输送泵、工字钢弯拱机、混凝土搅拌站等隧道工程设备！&lt;/span&gt;&lt;/p&gt;');
INSERT INTO `dr_1_anlixianchang_draft` (`id`, `cid`, `uid`, `catid`, `content`, `inputtime`) VALUES
(1, 10071, 2, 16, '{\"content\":\"&lt;p&gt;&lt;span style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; font-size: 16px; background-color: rgb(255, 255, 255);&quot;&gt;“豫工机械春季检修”是公司为助力客户高效施工而发起！每逢年后施工旺季，售后部门会评估重点设备的使用情况和时间节点，进行“大体检”、“大检修”，提升工作效率，延长使用寿命，为客户工程保驾护航，真正做到终身维护的承诺！到今天，豫工已坚持了18年。2023.2.3，春季检修按下启动键，豫工机械技术与售后服务部张工乘飞机，从郑州出发，飞往泰国曼谷，赶赴客户工地——中泰高铁项目Muak LeK隧道3-2出口，为客户在用的豫工隧道支护设备做检修保养。&lt;\\/span&gt;&lt;\\/p&gt;\",\"catid\":16,\"uid\":2,\"inputtime\":1680861271,\"updatetime\":1680861584,\"inputip\":\"123.52.22.36-17179\",\"displayorder\":0,\"hits\":1,\"title\":\"泰国调试液压湿喷机，助力一带一路建设！\",\"thumb\":\"\",\"keywords\":\"\",\"description\":\"\",\"author\":\"楠楠\",\"nrydbdt\":\"\",\"nrydbdbt\":\"混凝土输送泵泰国售后，助力一带一路建设\",\"nrydbxbt\":\"\",\"nrydbdljs\":\"客户负责中泰高铁——超前支护工程项目。2021年9月，客户首次咨询豫工液压湿喷机，工字钢弯拱机等设备，同时咨询了河南、湖南至少5个生产厂家。2021年12月5日，客户到访公司总部——郑州运营中心，并考察了豫工机械隧道支护设备生产基地。客户看到豫工门类齐全的设备生产线，庞大的仓库备货，完全满足其隧道物资一站式采购的需求，非常满意，从而达成合作意向！\",\"nrysgsp\":\"\",\"nrysgspfm\":\"\",\"nrykhhp\":\"\",\"nrysgxc\":\"\",\"status\":9,\"id\":10071}', 1680861588);
