(10045, 2, 22, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;生产效率高&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：上料斗与举料斗协同运作，不间断上料，喷浆量可达21㎥&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;承载能力大&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：知名汽车厂家生产底盘，适应各种野外作业！&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;应用范围广&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：四条液压支腿，设备平稳、牢固、安全，更适用工地施工。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;操作方便&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：速凝剂添加连续、均匀、无极变速。速凝剂工位，安全防护，加料轻松安全。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;人性化设计&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：机体两侧添加工作开关，操作更方便。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;坚固耐用&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：机架全部选用加厚型材，保证机体刚性，永不变形！&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;售后三包&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：一年质保，终生维修，24小时服务在线。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(10046, 2, 22, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;航空铝叶轮&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;：强度高。流线型叶轮，低噪音，大风量，寿命长。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;坚固耐用&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;：全铜芯耐高温特种电机，250℃正常运行1h,风机全身耐高压，加厚钢板。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;优质消音&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;：加厚孔板，优质消音棉制作，四级消音结构，噪音更低！&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;减少能耗&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 20px;&quot;&gt;：根据掘进面长度和巷道不同的通风要求，即可整机使用，又可分级使用，是隧道掘进局部通风的理想设备。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(10047, 2, 22, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;&lt;strong&gt;泵送压力大&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;适合低水灰高粘度砂浆注浆。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;&lt;strong&gt;施工效率高&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;上下两层搅拌，不间断供料，工作效率8m³/h。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;&lt;strong&gt;安全可靠&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;压力稳定，三道压力检测表，施工更安全。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;&lt;strong&gt;计量精确&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;最小分度置为0.IMpa,计量更为精确。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;&lt;strong&gt;操作简单&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;PLC智能数显，搅拌/储浆/注浆一体，使用方便。&lt;/span&gt;&lt;/p&gt;'),
(10048, 2, 22, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;strong&gt;外观平整&lt;/strong&gt;：确保台车强度合理，使二次衬砌的拱顶和边墙光滑平整，无错台，前后环搭接圆顺，矮边墙平直。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;strong&gt;成本低&lt;/strong&gt;：有限分析计算受力优化结构，在保证强度的前提下，减少台车用钢量，降低施工成本。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;strong&gt;通用性强&lt;/strong&gt;：实施标准化改造，大量运用标准件，推广台车的通用性，提高重复利用率；&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;strong&gt;安全简单&lt;/strong&gt;：推动台车人性化、自动化，降低人工成本，提高施工效率，降低施工风险。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(10049, 2, 21, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 20px;&quot;&gt;&lt;strong&gt;操作方便&lt;/strong&gt;：PLC智能控制，操作方便，加工数据可存储。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 20px;&quot;&gt;&lt;strong&gt;精准定位&lt;/strong&gt;：气动夹紧防跑偏，专业送料系统，精准加工。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 20px;&quot;&gt;&lt;strong&gt;耐用省钱&lt;/strong&gt;：设备配件精准加工，尺寸标准，耐磨耐用，成本价供应。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 20px;&quot;&gt;&lt;strong&gt;售后保障&lt;/strong&gt;：一年质保，售后三包，终身维护，24小时在线服务！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;');
